// Calculate total entries
let totalEntries = 0;
for (const cat of Object.keys(KNOWLEDGE_CORPUS)) {
    if (cat === 'meta') continue;
    if (Array.isArray(KNOWLEDGE_CORPUS[cat])) {
        totalEntries += KNOWLEDGE_CORPUS[cat].length;
    }
}
KNOWLEDGE_CORPUS.meta.total_entries = totalEntries;

class KnowledgeBase {
    constructor() {
        this.data = KNOWLEDGE_CORPUS;
        this.learned = [];
        this.index = this.buildIndex();
        this.stats = { entries: totalEntries, categories: Object.keys(this.data).filter(k => k !== 'meta').length, queries: 0, hits: 0 };
    }

    buildIndex() {
        const idx = new Map();
        for (const [category, entries] of Object.entries(this.data)) {
            if (category === 'meta' || !Array.isArray(entries)) continue;
            for (const entry of entries) {
                const tokens = (entry.q + ' ' + (entry.a || '') + ' ' + (entry.tags || []).join(' ')).toLowerCase().split(/\s+/);
                for (const token of new Set(tokens)) {
                    if (token.length < 2) continue;
                    if (!idx.has(token)) idx.set(token, []);
                    idx.get(token).push({ category, entry });
                }
            }
        }
        return idx;
    }

    search(query) {
        this.stats.queries++;
        const q = query.toLowerCase();
        const tokens = q.split(/\s+/).filter(t => t.length > 1);
        const results = new Map();
        for (const token of tokens) {
            const matches = this.index.get(token) || [];
            for (const { category, entry } of matches) {
                const key = entry.q;
                if (!results.has(key)) results.set(key, { entry, category, score: 0 });
                results.get(key).score += token.length > 4 ? 2 : 1;
            }
        }
        if (results.size === 0) {
            for (const token of tokens.slice(0, 3)) {
                for (const [cat, entries] of Object.entries(this.data)) {
                    if (cat === 'meta' || !Array.isArray(entries)) continue;
                    for (const entry of entries) {
                        const text = (entry.q + ' ' + (entry.a || '')).toLowerCase();
                        if (text.includes(token)) {
                            const key = entry.q;
                            if (!results.has(key)) results.set(key, { entry, category: cat, score: 0 });
                            results.get(key).score += 0.5;
                        }
                    }
                }
            }
        }
        const sorted = Array.from(results.values()).sort((a, b) => b.score - a.score).slice(0, 5);
        if (sorted.length > 0) this.stats.hits++;
        return sorted;
    }

    learn(question, answer, category = 'learned') {
        const entry = { q: question, a: answer, tags: ['learned', ...question.toLowerCase().split(/\s+/).slice(0, 5)], learned: true };
        this.learned.push(entry);
        const tokens = (entry.q + ' ' + entry.a).toLowerCase().split(/\s+/);
        for (const token of new Set(tokens)) {
            if (token.length < 2) continue;
            if (!this.index.has(token)) this.index.set(token, []);
            this.index.get(token).push({ category, entry });
        }
        this.stats.entries++;
        return entry;
    }

    getCategories() {
        return Object.keys(this.data).filter(k => k !== 'meta').map(cat => ({
            name: cat,
            count: Array.isArray(this.data[cat]) ? this.data[cat].length : 0,
            entries: Array.isArray(this.data[cat]) ? this.data[cat].slice(0, 3) : []
        }));
    }

    serialize() {
        const buf = Buffer.from(JSON.stringify({ version: KNOWLEDGE_VERSION, built: KNOWLEDGE_BUILD, stats: this.stats }));
        return { version: KNOWLEDGE_VERSION, built: KNOWLEDGE_BUILD, stats: this.stats, compressedSize: buf.length, compressed: buf.toString('base64').slice(0, 100) + '...' };
    }
}

module.exports = { KnowledgeBase, KNOWLEDGE_CORPUS };
